# Generated by google (gemini-2.5-flash)
# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(initial_balances, transactions):
    balances = initial_balances.copy()
    transaction_log = []

    for transaction in transactions:
        transaction_id = transaction['transaction_id']
        transaction_type = transaction['type']
        account_id = transaction['account_id']
        amount = transaction['amount']

        if account_id not in balances:
            transaction_log.append({
                'transaction_id': transaction_id,
                'status': 'failed',
                'reason': 'Account not found',
                'details': transaction
            })
            continue

        current_balance = balances[account_id]
        new_balance = current_balance

        if transaction_type == 'deposit':
            if amount <= 0:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Deposit amount must be positive',
                    'details': transaction
                })
                continue
            new_balance = current_balance + amount
            balances[account_id] = new_balance
            transaction_log.append({
                'transaction_id': transaction_id,
                'status': 'success',
                'previous_balance': current_balance,
                'new_balance': new_balance,
                'details': transaction
            })
        elif transaction_type == 'withdrawal':
            if amount <= 0:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Withdrawal amount must be positive',
                    'details': transaction
                })
                continue
            if current_balance < amount:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Insufficient funds',
                    'details': transaction
                })
                continue
            new_balance = current_balance - amount
            balances[account_id] = new_balance
            transaction_log.append({
                'transaction_id': transaction_id,
                'status': 'success',
                'previous_balance': current_balance,
                'new_balance': new_balance,
                'details': transaction
            })
        elif transaction_type == 'transfer':
            target_account_id = transaction.get('target_account_id')
            if not target_account_id:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Target account ID missing for transfer',
                    'details': transaction
                })
                continue
            if target_account_id not in balances:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Target account not found',
                    'details': transaction
                })
                continue
            if amount <= 0:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Transfer amount must be positive',
                    'details': transaction
                })
                continue
            if current_balance < amount:
                transaction_log.append({
                    'transaction_id': transaction_id,
                    'status': 'failed',
                    'reason': 'Insufficient funds for transfer',
                    'details': transaction
                })
                continue

            # Perform transfer
            balances[account_id] -= amount
            balances[target_account_id] += amount
            transaction_log.append({
                'transaction_id': transaction_id,
                'status': 'success',
                'sender_previous_balance': current_balance,
                'sender_new_balance': balances[account_id],
                'receiver_previous_balance': balances[target_account_id] - amount,
                'receiver_new_balance': balances[target_account_id],
                'details': transaction
            })
        else:
            transaction_log.append({
                'transaction_id': transaction_id,
                'status': 'failed',
                'reason': 'Unknown transaction type',
                'details': transaction
            })

    return balances, transaction_log